output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?duration WHERE {
  VALUES ?series {
    wd:Q1004352 wd:Q1004228 wd:Q3511262 wd:Q3511261
  }
  ?game wdt:P359 ?series ; wdt:P1347 ?homeTeam ; wdt:P1348 ?awayTeam .
  FILTER((?homeTeam = wd:Q33173 && ?awayTeam = wd:Q2271) ||(?homeTeam = wd:Q2271 && ?awayTeam = wd:Q33173))
  ?game wdt:P2047 ?duration .
}
ORDER BY DESC(?duration)
LIMIT 1
OFFSET 2

